#include <stdio.h>

void losa_zamjena(int x, int y);
void dobra_zamjena(int *p1, int *p2);

int main() {
	int a = 1, b = 999;
	
	printf("Pocetne vrijednosti:\n");
	printf("a = %d, b = %d\n", a, b); 
	printf("Losa zamjena:\n");
	losa_zamjena(a, b);
	printf("a = %d, b = %d\n", a, b); 
	printf("Dobra zamjena:\n");
	dobra_zamjena(&a, &b);
	printf("a = %d, b = %d\n", a, b); 
	
	return 0;
}

/* los primjer zamjene - funkcija ne moze promijeniti svoje parametre */
void losa_zamjena(int x, int y) {
	int temp;	
	temp = x;
	x = y;
	y = temp;
}

/* dobar primjer zamjene - funkcija ne moze promijeniti svoje parametre
   ali ako je parameter pokazivač, onda može promijeniti vrijednost na koju on pokazuje */
void dobra_zamjena(int *px, int *py) {
	int temp;
	temp = *px;
	*px = *py;
	*py = temp;
}
